export default {
  name: "ProgressBar",
  props: {
    percent: { type: Number, default: 0 },
    small: Boolean,
    active: Boolean,
    showProgress: Boolean,
    disableAnimations: Boolean,
  },
  computed: {
    progressStyle() {
      return {
        width: `${this.percentage}%`,
      };
    },
    percentage() {
      return (this.percent * 100).toFixed(2);
    },
  },
};
