import Board from "@/model/2048/Board";
import Square from "@/components/atoms/Square.vue";

export default {
  components: { Square },
  name: "Board",
  props: {
    size: {
      type: Number,
      required: true,
    },
    board: {
      type: [Board, Object],
      required: true,
    },
    transitionDuration: {
      type: Number,
      default: 0
    },
    gap: {
      type: Number,
      default: 0.25,
    },
  },
  computed: {
    boardStyle() {
      return {
        "grid-template-rows": `repeat(${this.size}, 1fr)`,
        "grid-template-columns": `repeat(${this.size}, 1fr)`,
        gap: `${this.gap}em`,
        padding: `${this.gap}em`,
      };
    },
  },
};
