export default {
  props: {
    size: {
      type: String,
    },
    theme: {
      type: String,
      default: "primary",
    },
    outlined: {
      type: Boolean,
      default: false,
    },
    type: {
      type: String,
      default: "button",
    },
    title: {
      type: String,
    },
    fab: Boolean,
    tag: { default: "button" },
    to: { type: [String, Object] },
  },
  methods: {
    handleClick(evt) {
      this.$emit("click", evt);
    },
  },
  computed: {
    classes() {
      return [
        `btn--${this.theme}`,
        this.size && `btn--${this.size}`,
        this.outlined && `btn--outlined`,
        this.fab && `btn--fab`,
      ];
    },
  },
};
